function getJuzSegments(juzNum) {
  const startMarker = JUZ_START.find(j => j.juz === juzNum);
  const endMarker = juzNum === 30 ? null : JUZ_START.find(j => j.juz === juzNum + 1);
  const segments = [];
  let cS = startMarker.s,
    cV = startMarker.v;
  while (true) {
    const surahInfo = SURAH_DATA.find(s => s.number === cS);
    if (!surahInfo) break;
    if (endMarker && cS === endMarker.s) {
      segments.push({
        s: cS,
        start: cV,
        end: endMarker.v - 1
      });
      break;
    } else {
      segments.push({
        s: cS,
        start: cV,
        end: surahInfo.verses
      });
      if (!endMarker && cS === 114) break;
      cS++;
      cV = 1;
    }
  }
  return segments;
}
function isJuzComplete(juzNum, prog) {
  return getJuzSegments(juzNum).every(seg => (prog[seg.s] || 0) >= seg.end);
}
function getAbsoluteVerseCount(surahNum, verseNum) {
  let total = 0;
  for (let i = 1; i < surahNum; i++) {
    const s = SURAH_DATA.find(x => x.number === i);
    if (s) total += s.verses;
  }
  return total + verseNum;
}
const JUZ_LIST = Array.from({
  length: 30
}, (_, i) => {
  const num = i + 1;
  const start = JUZ_START.find(j => j.juz === num);
  const surahName = SURAH_DATA.find(s => s.number === start.s).name;
  return {
    number: num,
    start: surahName + ' ayat ' + start.v
  };
});
function loadLocal(key, fallback) {
  try {
    const s = localStorage.getItem(key);
    if (s !== null) return JSON.parse(s);
  } catch (e) {}
  return fallback;
}
function saveLocal(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch (e) {}
}
function removeLocal(key) {
  try {
    localStorage.removeItem(key);
  } catch (e) {}
}

// Hitung ulang streak dari lastActiveDate mundur ke belakang,
// skip hari haid, berhenti di hari non-haid yang tidak ada di dailyLog
function recalcStreak(lastActive, haidLog) {
  if (!lastActive) return 0;
  const log = loadLocal('q-daily-log', {});
  let streak = 1;
  let cursor = new Date(lastActive);
  cursor.setDate(cursor.getDate() - 1);
  // Mundur maksimal 365 hari untuk keamanan
  for (let i = 0; i < 365; i++) {
    const k = cursor.toLocaleDateString('en-CA');
    if (haidLog[k]) {
      // Hari haid — skip, tidak putus streak
      cursor.setDate(cursor.getDate() - 1);
      continue;
    }
    if ((log[k] || 0) > 0) {
      // Hari baca — lanjut hitung streak
      streak++;
      cursor.setDate(cursor.getDate() - 1);
    } else {
      // Hari kosong non-haid — streak berhenti di sini
      break;
    }
  }
  return streak;
}
function parseTime12(timeStr) {
  if (!timeStr) return null;
  const parts = timeStr.trim().split(' ');
  const timeParts = parts[0].split(':');
  let h = parseInt(timeParts[0]);
  const m = parseInt(timeParts[1]);
  const period = parts[1];
  if (period === 'PM' && h !== 12) h += 12;
  if (period === 'AM' && h === 12) h = 0;
  return {
    h,
    m
  };
}
function toTime24(timeStr) {
  const t = parseTime12(timeStr);
  if (!t) return timeStr;
  return String(t.h).padStart(2, '0') + ':' + String(t.m).padStart(2, '0');
}
function toMinutes(h, m) {
  return h * 60 + m;
}

